import React, { useState, useEffect } from 'react';
import {
  Table,
  TableBody,
  TableCell,
  TableContainer,
  TableHead,
  TableRow,
  TextField,
  Button,
  Paper
} from '@mui/material';
import DeleteIcon from '@mui/icons-material/Delete';
import EditIcon from '@mui/icons-material/Edit';

function Pets() {
  // State hooks
  const [isLoaded, setIsLoaded] = useState(false);
  const [pets, setPets] = useState([]);
  const [formInputs, setFormInputs] = useState({ animal: '', description: '', age: '', price: '' });
  const [editingPetId, setEditingPetId] = useState(null);

  useEffect(() => {
    fetchPets();
  }, []);

  // Handlers and functions (fetchPets, handleInputChange, addOrUpdatePet, startEdit, cancelEdit)

  return (
    <div>
      {!isLoaded ? <div>Loading...</div> : (
        <>
          <TableContainer component={Paper}>
            <Table aria-label="simple table">
              <TableHead>
                <TableRow>
                  <TableCell>Animal</TableCell>
                  <TableCell>Description</TableCell>
                  <TableCell align="right">Age</TableCell>
                  <TableCell align="right">Price ($)</TableCell>
                  <TableCell align="right">Delete</TableCell>
                  <TableCell align="right">Edit</TableCell>
                </TableRow>
              </TableHead>
              <TableBody>
                {pets.map((pet) => (
                  <TableRow key={pet.id}>
                    <TableCell component="th" scope="row">{pet.animal}</TableCell>
                    <TableCell>{pet.description}</TableCell>
                    <TableCell align="right">{pet.age}</TableCell>
                    <TableCell align="right">{pet.price}</TableCell>
                    <TableCell align="right">
                      <Button onClick={() => deletePet(pet.id)}><DeleteIcon /></Button>
                    </TableCell>
                    <TableCell align="right">
                      <Button onClick={() => startEdit(pet)}><EditIcon /></Button>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </TableContainer>
          <div style={{ marginTop: '20px' }}>
            <TextField
              label="Animal"
              name="animal"
              value={formInputs.animal}
              onChange={handleInputChange}
              style={{ marginRight: '10px' }}
            />
            <TextField
              label="Description"
              name="description"
              value={formInputs.description}
              onChange={handleInputChange}
              style={{ marginRight: '10px' }}
            />
            <TextField
              label="Age"
              name="age"
              type="number"
              value={formInputs.age}
              onChange={handleInputChange}
              style={{ marginRight: '10px' }}
            />
            <TextField
              label="Price"
              name="price"
              type="number"
              value={formInputs.price}
              onChange={handleInputChange}
              style={{ marginRight: '10px' }}
            />
            <Button variant="contained" color="primary" onClick={addOrUpdatePet}>
              {editingPetId ? 'Update' : 'Add'} Pet
            </Button>
            {editingPetId && (
              <Button variant="contained" color="secondary" onClick={cancelEdit} style={{ marginLeft: '10px' }}>
                Cancel
              </Button>
            )}
          </div>
        </>
      )}
    </div>
  );
}

export default Pets;
